import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How is gestational age calculated?", a: "Gestational age is counted from the first day of your last menstrual period (LMP), not from conception. This is the medical standard. Most women conceive around day 14 of a 28-day cycle, which is why pregnancy is considered to start 2 weeks before actual conception. A full-term pregnancy is 40 weeks (280 days) from LMP." },
  { q: "When does morning sickness typically end?", a: "Morning sickness typically peaks between weeks 8-10 and subsides by weeks 12-14 for most people. About 10-15% of pregnant people experience symptoms beyond the first trimester (hyperemesis gravidarum). Eating small frequent meals, staying hydrated, and avoiding triggers can help manage nausea in early pregnancy." },
  { q: "What prenatal appointments should I expect?", a: "Standard prenatal visit schedule: every 4 weeks until week 28, every 2 weeks from weeks 28-36, then weekly from week 36 to delivery. Total: approximately 12-14 visits for uncomplicated pregnancies. High-risk pregnancies may require more frequent monitoring and additional ultrasounds." },
  { q: "What milestones happen in each trimester?", a: "1st trimester (weeks 1-12): all major organs and systems form - heart, brain, limbs. 2nd trimester (weeks 13-26): fetus grows rapidly, movement first felt, gender visible on ultrasound. 3rd trimester (weeks 27-40): major weight gain, lung maturation, baby moves into birth position." },
  { q: "What is the difference between gestational age and fetal age?", a: "Gestational age (from LMP) is 2 weeks longer than fetal age (from conception). A 12-week-gestational-age baby has been developing for approximately 10 weeks. Medical providers always use gestational age. When a fetal ultrasound says '10 weeks', it means 10 weeks from LMP." },
  { q: "What is a normal due date range?", a: "Only about 4% of babies are born exactly on their due date. A full-term pregnancy ranges from 39-40 weeks. 'Early term' is 37-38 weeks, 'full term' is 39-40 weeks, 'late term' is 41 weeks, and 'post-term' is 42+ weeks. Most hospitals consider delivery between 37-42 weeks as normal." },
  { q: "What happens at the 20-week anatomy scan?", a: "The anatomy scan (anomaly scan) at 18-22 weeks is the most detailed ultrasound of the pregnancy. It examines fetal anatomy including brain, heart, spine, kidneys, stomach, and limbs. It also measures growth, checks placenta position, amniotic fluid levels, and can usually confirm gender." },
  { q: "What is the viability milestone at 24 weeks?", a: "24 weeks is the current medical viability threshold - the point at which a premature baby has a meaningful chance of survival with intensive care. Survival rates: 24 weeks ~50-60%, 28 weeks ~80-90%, 32 weeks ~95%, 34+ weeks similar to full-term outcomes. Earlier births have higher rates of long-term complications." },
];

const MONTH_NAMES = ["January","February","March","April","May","June","July","August","September","October","November","December"];

const TRIMESTER_OVERVIEW = [
  ["1st Trimester", "Weeks 1-12", "Organ formation", "Fatigue, nausea, frequent urination"],
  ["2nd Trimester", "Weeks 13-26", "Rapid growth", "Energy returns, fetal movement, anatomy scan"],
  ["3rd Trimester", "Weeks 27-40", "Lung maturation, birth prep", "Swelling, back pain, Braxton-Hicks"],
];

export default function PregnancyCalculator() {
  const today = new Date();
  const [lmpStr, setLmpStr] = useState(new Date(today.getTime() - 80 * 24 * 3600000).toISOString().split("T")[0]);

  const lmp = new Date(lmpStr);
  const valid = !isNaN(lmp.getTime()) && lmp <= today;
  const dueDate = valid ? new Date(lmp.getTime() + 280 * 24 * 3600000) : null;
  const gestDays = valid ? Math.floor((today.getTime() - lmp.getTime()) / (24 * 3600000)) : 0;
  const gestWeeks = Math.floor(gestDays / 7);
  const gestRemDays = gestDays % 7;
  const daysLeft = dueDate ? Math.max(0, Math.ceil((dueDate.getTime() - today.getTime()) / (24 * 3600000))) : 0;
  const pctComplete = Math.min(100, Math.round((gestDays / 280) * 100));
  const trimester = gestWeeks < 13 ? 1 : gestWeeks < 27 ? 2 : 3;
  const fmtDate = (d: Date) => `${MONTH_NAMES[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;

  const MILESTONES = [
    { week: 8, label: "Heartbeat detectable by ultrasound" },
    { week: 12, label: "End of 1st trimester, risk drops significantly" },
    { week: 18, label: "Anatomy scan ultrasound" },
    { week: 20, label: "Halfway point" },
    { week: 24, label: "Viability milestone" },
    { week: 28, label: "3rd trimester begins" },
    { week: 37, label: "Early term" },
    { week: 39, label: "Full term" },
    { week: 40, label: "Due date" },
  ];

  return (
    <>
      <SEOHead
        title="Free Pregnancy Calculator Online - Calculate Due Date and Gestational Age Instantly | CalcHive"
        description="Free online pregnancy calculator. Calculate your gestational age, due date and trimester from your last menstrual period instantly. 100% free for everyone, no signup required."
        canonical="/pregnancy-calculator"
        keywords="free pregnancy calculator, gestational age calculator free online, pregnancy due date calculator free, free pregnancy week calculator, calculate pregnancy trimester free"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Pregnancy Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free pregnancy calculator to estimate gestational age, due date, and trimester from your last menstrual period. This gestational age calculator free online also works as a pregnancy due date calculator free, free pregnancy week calculator, and calculate pregnancy trimester free tool.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-8">
            <label htmlFor="lmp-pg" className="text-sm font-semibold text-foreground block mb-2">First Day of Last Menstrual Period (LMP)</label>
            <input id="lmp-pg" type="date" value={lmpStr} max={today.toISOString().split("T")[0]} onChange={e => setLmpStr(e.target.value)} className="w-full sm:w-auto px-4 py-2.5 rounded-xl border border-input bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          </div>
          {valid && dueDate ? (
            <motion.div key={lmpStr} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Gestational Age</p>
                <p className="text-6xl font-black text-white tracking-tight" data-testid="result-weeks">{gestWeeks}</p>
                <p className="text-white/70 text-sm mt-1">weeks + {gestRemDays} days - Trimester {trimester}</p>
              </div>
              <div className="mb-4">
                <div className="flex justify-between text-xs text-muted-foreground mb-1"><span>0 weeks</span><span>{pctComplete}% complete</span><span>40 weeks</span></div>
                <div className="h-3 bg-muted rounded-full overflow-hidden"><div className="h-full bg-gradient-to-r from-teal-400 to-teal-600 rounded-full transition-all" style={{ width: `${pctComplete}%` }} /></div>
              </div>
              <div className="grid grid-cols-3 gap-3 mb-6">
                {[
                  { label: "Due Date", value: fmtDate(dueDate) },
                  { label: "Days Remaining", value: `${daysLeft} days` },
                  { label: "Trimester", value: `${trimester}${trimester === 1 ? "st" : trimester === 2 ? "nd" : "rd"}` },
                ].map(({ label, value }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                    <p className="text-sm font-extrabold text-foreground">{value}</p>
                  </div>
                ))}
              </div>
              <div className="space-y-2">
                <p className="text-sm font-semibold text-foreground mb-2">Key Milestones</p>
                {MILESTONES.map(m => (
                  <div key={m.week} className={`flex items-center gap-3 px-4 py-2.5 rounded-xl border ${gestWeeks >= m.week ? "bg-teal-50 dark:bg-teal-950/30 border-teal-200 dark:border-teal-800" : "bg-muted/40 border-border"}`}>
                    <span className={`text-xs font-bold w-16 flex-shrink-0 ${gestWeeks >= m.week ? "text-teal-600 dark:text-teal-400" : "text-muted-foreground"}`}>Week {m.week}</span>
                    <span className={`text-xs ${gestWeeks >= m.week ? "text-foreground font-medium" : "text-muted-foreground"}`}>{m.label}</span>
                    {gestWeeks >= m.week && <span className="ml-auto text-teal-500 text-xs font-bold">Reached</span>}
                  </div>
                ))}
              </div>
            </motion.div>
          ) : <p className="text-center text-muted-foreground py-4">Enter your last menstrual period date to see your pregnancy progress.</p>}
        </section>
        <MedicalDisclaimer variant="pregnancy" /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Gestational Age for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Gestational age is calculated from the first day of the last menstrual period (LMP), not from conception. This 2-week difference exists because ovulation occurs around day 14 of a typical 28-day cycle. Medical providers worldwide use LMP-based gestational age for consistency.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Due Date = LMP Date + 280 days (40 weeks)</p>
            <p>Gestational Age = (Today - LMP) in weeks</p>
            <p>Days Remaining = Due Date - Today</p>
            <p className="text-xs text-muted-foreground mt-2">Also known as Naegele's rule: LMP + 1 year - 3 months + 7 days</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Your Due Date and Trimester</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Trimester", "Weeks", "Key Developments", "Common Symptoms"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {TRIMESTER_OVERVIEW.map(([tri, weeks, dev, sym]) => (
                  <tr key={tri} className={`hover:bg-muted/30 ${(trimester === 1 && tri === "1st Trimester") || (trimester === 2 && tri === "2nd Trimester") || (trimester === 3 && tri === "3rd Trimester") ? "bg-teal-50 dark:bg-teal-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-teal-600 dark:text-teal-400">{tri}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{weeks}</td>
                    <td className="py-2.5 px-4 text-foreground">{dev}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{sym}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Pregnancy Week Calculator for Every Mom</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Week", "Size Comparison", "Key Development"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["4", "Poppy seed", "Implantation occurs, embryo forms"],
                  ["8", "Kidney bean", "Heartbeat detectable, arms and legs forming"],
                  ["12", "Lime", "All major organs present, risk of miscarriage drops"],
                  ["16", "Avocado", "Gender may be visible, fetus can make facial expressions"],
                  ["20", "Banana", "Anatomy scan, baby actively moving"],
                  ["24", "Corn", "Viability milestone, lungs developing"],
                  ["28", "Eggplant", "3rd trimester begins, eyes can open"],
                  ["36", "Romaine lettuce", "Brain growth surge, baby gaining weight"],
                  ["40", "Watermelon", "Full term, ready for birth"],
                ].map(([week, size, dev]) => (
                  <tr key={week} className={`hover:bg-muted/30 ${gestWeeks === parseInt(week) ? "bg-teal-50 dark:bg-teal-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-teal-600 dark:text-teal-400">Week {week}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{size}</td>
                    <td className="py-2.5 px-4 text-foreground">{dev}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/pregnancy-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


